// // This module implements an 8-bit register with an active low synchronous reset. Data loads on the negative edge of the clock when the reset signal is high.
module top_module(
	input clk,
	input reset,
	input [7:0] data,
	output reg [7:0] q);always @(posedge clk)
	if (reset)
		q <= 0;
	else
		q <= data;

endmodule
